const cache = $input.all();
const config = $('⚙️ 생성 대상 선정').first().json;
if (cache.length > 0 && cache[0].json.id) {
  return [{json:{cache_hit:true,combo_key:config.combo_key,formula_name:cache[0].json.formula_name,message:'30일 이내 가이드 존재 - 스킵'}}];
}
return [{json:{cache_hit:false,product_type_kr:config.product_type_kr,category:config.category,skin_type_kr:config.skin_type_kr,combo_key:config.combo_key,ingredient_hints:config.ingredient_hints,run_id:config.run_id}}];

// ===== 원료 SQL WHERE절 미리 생성 =====
const config = $('🔀 캐시 히트?').first().json;
const hints = (config.ingredient_hints||'').split(',').map(h=>h.trim()).filter(h=>h.length>0);
const conditions = hints.map(h=>{
  const safe = h.replace(/'/g,"''");
  return "(LOWER(inci_name) LIKE LOWER('%"+safe+"%') OR LOWER(description) LIKE LOWER('%"+safe+"%'))";
}).join(' OR ');
const sql = 'SELECT inci_name, korean_name, cas_number, description FROM ingredient_master WHERE inci_name IS NOT NULL AND ('+conditions+') ORDER BY RANDOM() LIMIT 50';
return [{json:{ingredient_sql:sql,product_type_kr:config.product_type_kr,category:config.category,skin_type_kr:config.skin_type_kr,combo_key:config.combo_key,run_id:config.run_id}}];

// ===== Claude 프롬프트 (base64 + 참조제품 + claude -p만 사용) =====
const config = $('🔄 원료 SQL 생성').first().json;
const ingredients = $('📦 원료 DB 조회').all().map(i=>i.json);
const regulations = $('📋 규제 DB 조회').all().map(i=>i.json);
const refProducts = $('📦 참조제품 조회').all().map(i=>i.json);

const ingList = ingredients.map(i=>
  i.inci_name+' ('+(i.korean_name||'-')+') CAS:'+(i.cas_number||'-')
).join('\n');
const regList = regulations.map(r=>
  r.inci_name+': '+r.restriction+' (최대 '+(r.max_concentration||'미정')+')'
).join('\n');

let refSection = '';
if (refProducts.length > 0) {
  refSection = '\n\n[참조 시판 제품 (전성분 참고용)]\n';
  refProducts.forEach((p,i)=>{
    refSection += (i+1)+'. '+(p.brand_name||'')+' '+(p.product_name||'')+'\n';
    refSection += '   전성분: '+((p.full_ingredients||'').substring(0,300))+'\n';
  });
  refSection += '\n위 시판 제품의 전성분 구성을 참고하되, 동일하지 않은 독창적 처방을 만들어줘.\n';
}

const prompt = '너는 화장품 처방 전문가야. 아래 조건에 맞는 가이드처방을 만들어줘.\n\n'
  +'[처방 조건]\n'
  +'- 제품 유형: '+config.product_type_kr+' ('+config.category+')\n'
  +'- 대상 피부: '+config.skin_type_kr+'\n\n'
  +'[사용 가능 원료 목록 (DB 기준 '+ingredients.length+'건)]\n'+ingList+'\n\n'
  +'[규제 정보 ('+regulations.length+'건)]\n'+regList
  +refSection+'\n\n'
  +'반드시 아래 JSON 형식만 출력해. 다른 텍스트 없이 JSON만.\n'
  +'{\n'
  +'  "product_type": "'+config.product_type_kr+'",\n'
  +'  "skin_type": "'+config.skin_type_kr+'",\n'
  +'  "formula_name": "처방명 한국어",\n'
  +'  "total_ingredients": 숫자,\n'
  +'  "phases": [{\n'
  +'    "phase": "A (수상)",\n'
  +'    "temperature": "70-75도",\n'
  +'    "ingredients": [{"inci_name":"성분명","korean_name":"한국어명","wt_percent":배합비숫자,"function":"기능"}]\n'
  +'  }],\n'
  +'  "total_wt_percent": 100.00,\n'
  +'  "estimated_ph": 5.5,\n'
  +'  "estimated_viscosity_cp": 15000,\n'
  +'  "process_steps": ["공정1","공정2"],\n'
  +'  "quality_checks": ["체크1"],\n'
  +'  "notes": "특이사항"\n'
  +'}\n\n'
  +'규칙: 배합비 합계 반드시 100.00%. 규제 제한 농도 초과 금지. Phase별 온도/공정 포함. 현실 제조 가능한 처방.';

const promptB64 = Buffer.from(prompt,'utf-8').toString('base64');
// 수정1: --output-format 제거, claude -p 만 사용
// 수정2: head -c 50000 으로 변경
const command = 'cd /home/kpros && echo "'+promptB64+'" | base64 -d > /tmp/guide_prompt.txt && cat /tmp/guide_prompt.txt | /home/kpros/.npm-global/bin/claude -p 2>/dev/null | head -c 50000';

return [{json:{
  command, combo_key:config.combo_key,
  product_type_kr:config.product_type_kr, skin_type_kr:config.skin_type_kr,
  ingredient_count:ingredients.length, regulation_count:regulations.length,
  ref_product_count:refProducts.length
}}];

// ===== 파싱 & 검증 + 싱글쿼트 이스케이핑 =====
const input = $input.first().json;
const config = $('🧠 Claude 프롬프트 구성').first().json;
let guide = {};
try {
  const stdout = (input.stdout||'').trim();
  // JSON 블록 추출 (마크다운 코드블록 제거)
  let jsonStr = stdout.replace(/```json\s*/g,'').replace(/```\s*/g,'').trim();
  const jsonMatch = jsonStr.match(/\{[\s\S]*\}/);
  if (jsonMatch) { guide = JSON.parse(jsonMatch[0]); }
  else { guide = JSON.parse(jsonStr); }
} catch(e) {
  guide = {
    product_type:config.product_type_kr, skin_type:config.skin_type_kr,
    formula_name:config.combo_key+' (파싱실패)',
    raw_output:(input.stdout||'').substring(0,3000), parse_error:e.message
  };
}
// 배합비 검증
let totalWt = 0;
if (guide.phases) {
  guide.phases.forEach(ph=>{
    (ph.ingredients||[]).forEach(ing=>{ totalWt += parseFloat(ing.wt_percent)||0; });
  });
}
const guideJson = JSON.stringify(guide);
const guideEscaped = guideJson.replace(/'/g,"''");
const fileB64 = Buffer.from(guideJson,'utf-8').toString('base64');
return [{json:{
  combo_key:config.combo_key,
  product_type_kr:config.product_type_kr, skin_type_kr:config.skin_type_kr,
  guide_data_escaped:guideEscaped,
  formula_name:(guide.formula_name||config.combo_key).replace(/'/g,"''"),
  total_wt_percent:totalWt.toFixed(2),
  wt_valid:Math.abs(totalWt-100)<0.1,
  estimated_ph:guide.estimated_ph||null,
  estimated_viscosity:guide.estimated_viscosity_cp||null,
  has_error:!!guide.parse_error,
  file_b64:fileB64
}}];

// ===== 실행 리포트 =====
const cacheCheck = $('🔀 캐시 히트?').first().json;
if (cacheCheck.cache_hit) {
  return [{json:{
    report:'⏭️ 캐시 히트 - 스킵',
    combo_key:cacheCheck.combo_key,
    formula_name:cacheCheck.formula_name,
    action:'skipped', cost:'0원'
  }}];
}
const result = $('🔄 처방 파싱 & 검증').first().json;
const info = $('🧠 Claude 프롬프트 구성').first().json;
return [{json:{
  report:'✅ 가이드처방 생성 완료',
  combo_key:result.combo_key,
  formula_name:result.formula_name,
  wt_valid:result.wt_valid,
  total_wt:result.total_wt_percent+'%',
  ph:result.estimated_ph,
  viscosity:result.estimated_viscosity,
  has_error:result.has_error,
  ingredients_used:info.ingredient_count,
  regulations_checked:info.regulation_count,
  ref_products_used:info.ref_product_count,
  action:'generated', cost:'0원 (Claude Code Max)',
  saved:'guide_cache + data/learning/ + E:/backup/formulations/',
  timestamp:new Date().toISOString(),
  next_run:new Date(Date.now()+4*60*60*1000).toISOString()
}}];
